const LS_OK=(()=>{try{const k="__sc_t";window.localStorage.setItem(k,"1");window.localStorage.removeItem(k);return true;}catch(e){return false;}})();
const lsGet=(k,fb)=>{ if(!LS_OK)return fb; try{const v=window.localStorage.getItem("sc_"+k);return v==null?fb:JSON.parse(v);}catch(e){return fb;} };
const lsSet=(k,v)=>{ if(!LS_OK)return; try{window.localStorage.setItem("sc_"+k,JSON.stringify(v));}catch(e){} };
const lsRaw=(k)=>{ if(!LS_OK)return null; try{return window.localStorage.getItem("sc_"+k);}catch(e){return null;} };
const lsDel=(k)=>{ if(!LS_OK)return; try{window.localStorage.removeItem("sc_"+k);}catch(e){} };
// Which login is active. Every non-global key is stored under this account so each login keeps its OWN settings/data.
const activeUid=()=>{ try{const s=lsGet("session",null); const id=s&&(s.id||s.email); return id?String(id):"guest"; }catch(e){return "guest";} };
// Shared across all logins (never namespaced): the accounts list + who is signed in.
const GLOBAL_KEYS={session:1,users:1,signupRequests:1,featureFlags:1,myFeatures:1,customFeatures:1,fedexRequests:1,publicBrand:1,myAccess:1,companyUsers:1,companyFlags:1,companyAdminRequests:1,rateRules:1};
// Scratch = the in-progress shipment. Per-login, but starts blank on each login (never migrated/inherited).
const isScratch=(key)=>String(key).indexOf("ship.")===0;
// Scratch keys wiped on login so the receiver + package dims are always blank for a fresh session.
const SCRATCH_KEYS=["ship.receiver","ship.pieces","ship.reference","ship.invoiceNo","ship.poNo","ship.insurance","ship.residential"];
const clearScratchFor=(uid)=>SCRATCH_KEYS.forEach(k=>lsDel("u/"+uid+"/"+k));

/* Copilot: does an order match a Claude-staged batch filter? Pure, testable. */
function batchCmdMatch(o,f,zone){
  const has=(arr)=>Array.isArray(arr)&&arr.length;
  if(f.productContains&&!String(o.items||o.product||"").toLowerCase().includes(String(f.productContains).toLowerCase()))return false;
  if(has(f.skus)&&!f.skus.map(x=>String(x).toLowerCase()).includes(String(o.sku||"").toLowerCase()))return false;
  if(has(f.states)&&!f.states.map(x=>String(x).toUpperCase()).includes(String(o.state||"").toUpperCase()))return false;
  if(has(f.zones)&&!f.zones.map(String).includes(String(zone)))return false;
  if(has(f.sources)&&!f.sources.map(x=>String(x).toLowerCase()).includes(String(o.source||"Manual").toLowerCase()))return false;
  const w=+o.weight||0,t=parseFloat(o.total||0);
  if(f.weightMin!=null&&w<+f.weightMin)return false;
  if(f.weightMax!=null&&w>+f.weightMax)return false;
  if(f.totalMin!=null&&t<+f.totalMin)return false;
  if(f.totalMax!=null&&t>+f.totalMax)return false;
  if(f.ageMaxDays!=null||f.ageMinDays!=null){
    const tt=Date.parse(o.date||"");if(isNaN(tt))return false;
    const a=Math.max(0,Math.floor((Date.now()-tt)/86400000));
    if(f.ageMaxDays!=null&&a>+f.ageMaxDays)return false;
    if(f.ageMinDays!=null&&a<+f.ageMinDays)return false;
  }
  return true;
}

