      if(g.dimL!=null&&qL!=null&&(g.dimL>qL+0.5||g.dimW>qW+0.5||g.dimH>qH+0.5)) reasons.push({t:"dim",label:`Larger size billed: ${qL}×${qW}×${qH} → ${g.dimL}×${g.dimW}×${g.dimH} in`});
